                3,
                attempt => TimeSpan.FromSeconds(Math.Pow(2, attempt)),
                (ex, ts, retry, ctx) =>
                {
                    // TODO: Replace with your ILogger if you want
                    Console.WriteLine($"[Polly] Retry {retry} after {ts.TotalSeconds}s: {ex.Message}");
